const payload = typeof msg.payload === 'string'
    ? JSON.parse(msg.payload)
    : msg.payload;

const currentAccum   = payload.rain_accumulated ?? 0;
const previousAccum  = flow.get('previous_rain_accumulated') ?? null;
const precipType     = payload.precipitation_type ?? 'None';

// Delta-based intensity — guard against midnight reset and first run
const delta = previousAccum !== null ? currentAccum - previousAccum : null;
const observedIntensity = delta !== null && delta > 0
    ? Math.round(delta * 60 * 1000) / 1000
    : (precipType !== 'None' ? 0.01 : 0);

flow.set('previous_rain_accumulated', currentAccum);
flow.set('station_rain_accumulated',  currentAccum);
flow.set('station_precip_type',       precipType);
flow.set('observed_intensity',        observedIntensity);

return null;

// Inject synthetic data that mimics rain starting in 10 minutes
// Bypasses the API call entirely — goes straight to Analyze Minutely

const now = Math.floor(Date.now() / 1000);

// Build 61 synthetic minutely entries
// Minutes 0-9: dry, Minutes 10-60: rain
const minutely = [];
for (let i = 0; i < 61; i++) {
    const active = i >= 10;
    minutely.push({
        time:               now + (i * 60),
        precip_intensity:   active ? 0.05 + (Math.random() * 0.3) : 0,
        precip_probability: active ? 0.75 : 0,
        precip_error:       active ? 0.01 : 0,
        precip_type:        active ? 'rain' : 'none',
        rain_intensity:     active ? 0.05 : 0,
        snow_intensity:     0,
        sleet_intensity:    0
    });
}

msg.payload = {
    fetched_at: new Date().toISOString(),
    cape:       0,
    minutely
};

return msg;

const now = Math.floor(Date.now() / 1000);

const minutely = Array.from({ length: 61 }, (_, i) => ({
    time:               now + (i * 60),
    precip_intensity:   0,
    precip_probability: 0,
    precip_error:       0,
    precip_type:        'none',
    rain_intensity:     0,
    snow_intensity:     0,
    sleet_intensity:    0
}));

msg.payload = {
    fetched_at: new Date().toISOString(),
    cape:       0,
    minutely
};

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const canonical = global.get('weather_canonical') ?? {};
const sources = canonical.sources ?? {};

// Check minutely freshness
const minutelyFetchedAt = sources.minutely?.fetched_at;
if (!minutelyFetchedAt) {
    node.status({ fill: 'grey', shape: 'ring', text: formatStatus('Waiting for OWM data') });
    return null;
}
const minutelyAgeMinutes = (Date.now() - new Date(minutelyFetchedAt).getTime()) / 60000;
if (minutelyAgeMinutes > 5) {
    node.warn(`weather_canonical.minutely is ${Math.round(minutelyAgeMinutes)}m stale — skipping`);
    node.status({ fill: 'red', shape: 'ring', text: formatStatus(`OWM stale ${Math.round(minutelyAgeMinutes)}m`) });
    return null;
}

// Get CAPE from convective section — current hour lookup
let cape = 0;
if (canonical.convective?.length > 0) {
    const currentHour = new Date().toISOString().slice(0, 13);
    const convNow = canonical.convective.find(e => e.time.startsWith(currentHour));
    cape = convNow?.cape ?? 0;
}

// Map canonical minutely to the shape Analyze Minutely expects
const minutely = (canonical.minutely ?? []).map(m => ({
    time: m.time,
    precip_intensity: m.precip_intensity,
    precip_probability: m.precip_probability,
    precip_error: null,
    precip_type: m.precip_type,
    rain_intensity: m.precip_type === 'rain' ? m.precip_intensity : 0,
    snow_intensity: m.precip_type === 'snow' ? m.precip_intensity : 0,
    sleet_intensity: m.precip_type === 'sleet' ? m.precip_intensity : 0
}));

if (minutely.length === 0) {
    node.status({ fill: 'grey', shape: 'ring', text: formatStatus('Empty minutely') });
    return null;
}

// Replace minutely[0] with Tempest ground truth
const stationPrecipType = flow.get('station_precip_type') ?? 'None';
const observedIntensity = flow.get('observed_intensity') ?? 0;
const isActive = stationPrecipType !== 'None';

// When Tempest says it's raining, clamp intensity to at least the Analyze Minutely
// threshold (0.02 in/hr). The fallback observedIntensity of 0.01 (no measurable delta
// between readings) would otherwise cause has_threat to oscillate false while rain
// continues, desynchronising notification_active from device state.
const groundTruthIntensity = isActive ? Math.max(observedIntensity, 0.021) : observedIntensity;

if (minutely.length > 0) {
    minutely[0] = {
        ...minutely[0],
        precip_intensity: groundTruthIntensity,
        precip_probability: isActive ? 1.0 : minutely[0].precip_probability,
        precip_type: isActive ? stationPrecipType.toLowerCase() : minutely[0].precip_type,
        rain_intensity: stationPrecipType.toLowerCase() === 'rain' ? groundTruthIntensity : 0,
        snow_intensity: stationPrecipType.toLowerCase() === 'snow' ? groundTruthIntensity : 0,
        sleet_intensity: stationPrecipType.toLowerCase() === 'sleet' ? groundTruthIntensity : 0,
        source: 'tempest'
    };
}

msg.payload = {
    fetched_at: minutelyFetchedAt,
    cape,
    minutely
};

node.status({
    fill: 'green', shape: 'dot',
    text: formatStatus(`${minutely.length} min | CAPE ${cape}`)
});
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const p = msg.payload;
const minutely = p.minutely;

// --- Thresholds ---
const PROB_THRESHOLD      = 0.60;  // provisional
const INTENSITY_THRESHOLD = 0.02;  // in/hr — ignore trace amounts

// --- Helper: is a given minute considered active precipitation? ---
function isActive(m) {
    return m.precip_probability >= PROB_THRESHOLD
        && m.precip_intensity   >= INTENSITY_THRESHOLD;
}

// --- Scan minutely into windows ---
const windows = [];
let windowStart = 0;
let currentActive = isActive(minutely[0]);

for (let i = 1; i <= minutely.length; i++) {
    const active = i < minutely.length ? isActive(minutely[i]) : !currentActive;
    if (active !== currentActive) {
        windows.push({
            start_idx:  windowStart,
            end_idx:    i - 1,
            active:     currentActive,
            minutes:    minutely.slice(windowStart, i)
        });
        windowStart   = i;
        currentActive = active;
    }
}

const precipWindows = windows.filter(w => w.active);

function analyzeWindow(w) {
    let peakIntensity   = 0;
    let peakProbability = 0;
    const types = new Set();

    for (const m of w.minutes) {
        if (m.precip_intensity > peakIntensity) {
            peakIntensity   = m.precip_intensity;
            peakProbability = m.precip_probability;
        }
        if (m.rain_intensity  > 0) types.add('rain');
        if (m.snow_intensity  > 0) types.add('snow');
        if (m.sleet_intensity > 0) types.add('sleet');
    }

    return {
        start_idx:        w.start_idx,
        end_idx:          w.end_idx,
        duration_min:     w.end_idx - w.start_idx + 1,
        peak_intensity:   Math.round(peakIntensity * 1000) / 1000,
        peak_probability: Math.round(peakProbability * 100) / 100,
        types:            [...types]
    };
}

const analyzedWindows = precipWindows.map(analyzeWindow);

const hasThreat      = analyzedWindows.length > 0;
const isIntermittent = analyzedWindows.length > 1;
const firstWindow    = analyzedWindows[0] ?? null;
const lastWindow     = analyzedWindows[analyzedWindows.length - 1] ?? null;
const extendsToEnd   = lastWindow ? lastWindow.end_idx === minutely.length - 1 : false;

const allTypes    = [...new Set(analyzedWindows.flatMap(w => w.types))];
const overallPeak = Math.max(...analyzedWindows.map(w => w.peak_intensity), 0);

msg.payload = {
    ...p,
    analysis: {
        has_threat:      hasThreat,
        is_intermittent: isIntermittent,
        extends_to_end:  extendsToEnd,
        onset_minutes:   firstWindow?.start_idx ?? null,
        clear_minutes:   hasThreat ? (extendsToEnd ? null : (lastWindow.end_idx + 1)) : null,
        all_types:       allTypes,
        peak_intensity:  Math.round(overallPeak * 1000) / 1000,
        windows:         analyzedWindows
    }
};

node.status({
    fill: hasThreat ? 'yellow' : 'green',
    shape: 'dot',
    text: formatStatus(
        hasThreat
            ? `${isIntermittent ? 'Intermittent' : 'Continuous'} — onset +${firstWindow.start_idx}min`
            : 'No threat'
    )
});

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const p = msg.payload;
const a = p.analysis;
const cape = p.cape ?? 0;

const HEAVY_RAIN   = 0.30;
const HEAVY_SNOW   = 0.10;
const THUNDER_CAPE = 500;

function capitalize(str) {
    return str.charAt(0).toUpperCase() + str.slice(1);
}

function typeLabel(types, peakIntensity, cape) {
    const thunder = cape >= THUNDER_CAPE;
    const hasRain  = types.includes('rain');
    const hasSnow  = types.includes('snow');
    const hasSleet = types.includes('sleet');

    let primary;
    if      (hasRain && hasSnow && hasSleet) primary = 'rain, snow, and sleet';
    else if (hasRain && hasSnow)             primary = 'rain and snow';
    else if (hasRain && hasSleet)            primary = 'rain and sleet';
    else if (hasSnow && hasSleet)            primary = 'snow and sleet';
    else if (hasRain)                        primary = 'rain';
    else if (hasSnow)                        primary = 'snow';
    else if (hasSleet)                       primary = 'sleet';
    else                                     primary = 'precipitation';

    if (thunder) {
        primary = primary
            .replace(/^rain/, 'thunderstorms')
            .replace(/^snow/, 'thundersnow')
            .replace(/^sleet/, 'thundersleet');
    }

    if (!thunder && types.length === 1) {
        if (hasRain && peakIntensity > HEAVY_RAIN) primary = 'heavy rain';
        if (hasSnow && peakIntensity > HEAVY_SNOW) primary = 'heavy snow';
    }

    return primary;
}

function minuteText(n) {
    return `${n} minute${n === 1 ? '' : 's'}`;
}

const stationPrecipType = flow.get('station_precip_type') ?? 'None';
const currentlyActive   = stationPrecipType !== 'None';

let message     = null;
let threat_type = null;

if (a.has_threat) {
    const label = typeLabel(a.all_types, a.peak_intensity, cape);
    threat_type = capitalize(label);

    if (!currentlyActive) {
        const onset = a.onset_minutes;
        if (a.is_intermittent) {
            message = onset === 0
                ? `Periods of ${label} starting shortly`
                : `Periods of ${label} starting in ${minuteText(onset)}`;
        } else {
            message = onset === 0
                ? `${capitalize(label)} starting shortly`
                : `${capitalize(label)} starting in ${minuteText(onset)}`;
        }
    } else {
        if (a.is_intermittent) {
            message = `Periods of ${label} for the next ${minuteText(a.clear_minutes ?? 60)}`;
        } else if (a.extends_to_end) {
            message = `${capitalize(label)} continuing for at least 60 minutes`;
        } else {
            message = `${capitalize(label)} stopping in ${minuteText(a.clear_minutes)}`;
        }
    }
}

msg.payload = {
    ...p,
    message,
    threat_type,
    has_threat:       a.has_threat,
    currently_active: currentlyActive
};

node.status({
    fill:  message ? 'yellow' : 'green',
    shape: 'dot',
    text:  formatStatus(message ?? 'Clear')
});

return msg;

const p = msg.payload;
const a = p.analysis;

node.send([{
    topic:   'highland/state/weather/analysis',
    retain:  true,
    payload: JSON.stringify({
        timestamp:       p.fetched_at,
        has_threat:      a.has_threat,
        onset_minutes:   a.onset_minutes,
        clear_minutes:   a.clear_minutes,
        is_intermittent: a.is_intermittent,
        extends_to_end:  a.extends_to_end,
        all_types:       a.all_types,
        peak_intensity:  a.peak_intensity,
        cape:            p.cape,
        message:         p.message,
        threat_type:     p.threat_type,
        source:          'open_weather_map',
        minutely:        p.minutely.map(m => ({
            t: m.time,
            i: m.precip_intensity,
            p: m.precip_probability,
            k: m.precip_type
        }))
    })
}, null]);

node.status({ fill: 'green', shape: 'dot', text: 'Published' });

return [null, msg];

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const p = msg.payload;
const CORRELATION_ID = 'weather_precip_forecast';
const IMAGE_URL = `http://home.local:8123/local/hub.local/weather/radar/reflectivity.gif?t=${Math.floor(Date.now() / 1000)}`;

const wasActive = flow.get('notification_active') ?? false;

if (!p.has_threat) {
    if (wasActive) {
        flow.set('notification_active', false);
        node.status({ fill: 'green', shape: 'dot', text: formatStatus('Cleared') });
        node.send([{
            topic: 'highland/command/notify/clear',
            payload: JSON.stringify({
                correlation_id: CORRELATION_ID,
                notification_id: 'weather.precip_forecast'
            })
        }, msg]);
    } else {
        node.status({ fill: 'green', shape: 'dot', text: formatStatus('No threat') });
        node.send([null, msg]);
    }
} else {
    flow.set('notification_active', true);
    const action = wasActive ? 'Updated' : 'Created';
    node.status({ fill: 'yellow', shape: 'dot', text: formatStatus(`${action}: ${p.message}`) });
    node.send([{
        topic: 'highland/event/notify',
        payload: JSON.stringify({
            correlation_id: CORRELATION_ID,
            notification_id: 'weather.precip_forecast',
            source: 'weather_analysis',
            title: 'Weather Alert',
            message: p.message,
            media: { image: IMAGE_URL },
            url: 'homeassistant://navigate/dashboard-weather/0?server=default',
            sticky: true
        })
    }, msg]);
}

return null;

const STATE_TOPIC = 'highland/state/weather/analysis';
const base        = 'homeassistant/sensor/highland_weather_analysis';

const device = {
    identifiers:  ['highland_weather_analysis'],
    name:         'Highland Weather Analysis',
    model:        'OpenWeatherMap and Open-Meteo',
    manufacturer: 'Highland'
};

node.send({
    topic:   `${base}/analysis/config`,
    retain:  true,
    qos:     1,
    payload: JSON.stringify({
        name:                  'Weather Analysis',
        unique_id:             'highland_weather_analysis',
        state_topic:           STATE_TOPIC,
        value_template:        "{{ value_json.threat_type if value_json.threat_type else 'Clear' }}",
        json_attributes_topic: STATE_TOPIC,
        icon:                  'mdi:weather-rainy',
        device
    })
});

return null;

const config = global.get('config');
const key = config.secrets.open_weather_map.api_key;
const lat = config.location.latitude;
const lon = config.location.longitude;

msg.url = `https://api.openweathermap.org/data/3.0/onecall?lat=${lat}&lon=${lon}&exclude=current,daily,alerts&appid=${key}&units=imperial`;

flow.set('owm_tick_count', 0);

return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const d = msg.payload;

function owmIdToPrecipType(id) {
    if (!id) return 'none';
    if (id === 511) return 'sleet';
    if (id >= 600 && id <= 622) return 'snow';
    if (id >= 500 && id <= 531) return 'rain';
    if (id >= 300 && id <= 321) return 'rain';
    return 'none';
}

// Build hourly lookup maps for pop and weather code
const popByHour  = {};
const typeByHour = {};
(d.hourly || []).forEach(h => {
    const key = Math.floor(h.dt / 3600) * 3600;
    popByHour[key]  = h.pop ?? 0;
    typeByHour[key] = h.weather?.[0]?.id ?? null;
});

const minutely = (d.minutely || []).map(m => {
    const hourKey   = Math.floor(m.dt / 3600) * 3600;
    const intensity = Math.round(m.precipitation * 0.0393701 * 1000) / 1000;
    const pop       = popByHour[hourKey] ?? 0;
    const typeId    = typeByHour[hourKey] ?? null;
    return {
        time:               m.dt,
        precip_intensity:   intensity,
        precip_probability: pop,
        precip_type:        intensity > 0 ? owmIdToPrecipType(typeId) : 'none',
        source:             'open_weather_map'
    };
});

const canonical          = global.get('weather_canonical') ?? {};
canonical.minutely       = minutely;
canonical.sources        = canonical.sources ?? {};
canonical.sources.minutely = { provider: 'open_weather_map', fetched_at: new Date().toISOString() };
global.set('weather_canonical', canonical);

node.status({ fill: 'green', shape: 'dot',
    text: formatStatus(`${minutely.length} min — ${new Date().toLocaleTimeString()}`) });
return null;

const config = global.get('config');
const lat = config.location.latitude;
const lon = config.location.longitude;

msg.url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&hourly=cape,lifted_index,convective_inhibition&models=gfs_seamless&forecast_days=1`;
return msg;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
const d = msg.payload;

const hourly = d.hourly;
const convective = hourly.time.map((t, i) => ({
    time:                  t,
    cape:                  hourly.cape[i],
    lifted_index:          hourly.lifted_index[i],
    convective_inhibition: hourly.convective_inhibition[i]
}));

const canonical             = global.get('weather_canonical') ?? {};
canonical.convective        = convective;
canonical.sources           = canonical.sources ?? {};
canonical.sources.convective = { provider: 'open_meteo', fetched_at: new Date().toISOString() };
global.set('weather_canonical', canonical);

node.status({ fill: 'green', shape: 'dot',
    text: formatStatus(`${convective.length} hours — ${new Date().toLocaleTimeString()}`) });
return null;

const p = msg.payload;

const hasThreat   = p.has_threat;
const tempestRain = (flow.get('station_precip_type') ?? 'None') !== 'None';
const shouldBeActive = hasThreat || tempestRain;

const newState = shouldBeActive ? 'active' : 'dormant';
flow.set('owm_poll_state', newState);

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);
node.status({
    fill:  newState === 'active' ? 'yellow' : 'green',
    shape: 'dot',
    text:  formatStatus(`${newState.toUpperCase()}`)
});

return msg;

const state     = flow.get('owm_poll_state') ?? 'active';
const tickCount = (flow.get('owm_tick_count') ?? 0) + 1;
flow.set('owm_tick_count', tickCount);

// ACTIVE: pass every tick (every 1 min)
// DORMANT: pass every 5th tick (every 5 min)
const passThrough = state === 'active' || (tickCount % 5 === 0);

node.status({
    fill:  state === 'active' ? 'yellow' : 'green',
    shape: 'dot',
    text:  `${state.toUpperCase()} | Tick ${tickCount}`
});

if (!passThrough)
{
    return null;
}

return msg;
